ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?major ?campus WHERE {
  ?students a :Students .
  ?students p:Major ?major .
  ?students p:Campus ?campus .
  ?students p:name ?fullname_lk .
  FILTER(REGEX(STR(?fullname_lk), "^.*\\ Smith$"))
} }
  full: { SELECT ?major ?city ?campus WHERE {
  ?students a :Students .
  ?students p:Major ?major .
  ?students p:City ?city .
  ?students p:Campus ?campus .
  ?students p:name ?fullname_lk .
  FILTER(REGEX(STR(?fullname_lk), "^.*\\ Smith$"))
} }
  component_2: { SELECT ?major ?city WHERE {
  ?students a :Students .
  ?students p:Major ?major .
  ?students p:City ?city .
  ?students p:name ?fullname_lk .
  FILTER(REGEX(STR(?fullname_lk), "^.*\\ Smith$"))
} }
}

PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
